import{_ as a}from"./CTWAalkl.js";import{e as t,u as s,c as i,a as n,b as r,w as d,x as l,o as c,d as p}from"./Dw-snFKg.js";const m={class:"min-h-screen bg-white text-zinc-900 pt-24 pb-12 px-6"},u={class:"max-w-3xl mx-auto"},v=t({__name:"aviso-legal",setup(x){return s({title:"Aviso Legal - Tortillas Kombat"}),(b,e)=>{const o=a;return c(),i("div",m,[n("div",u,[r(o,{to:"/",class:"font-header text-zinc-900 hover:text-amber-600 mb-6 inline-block uppercase tracking-widest text-sm transition-colors border-b-2 border-zinc-900 hover:border-amber-600 pb-1"},{default:d(()=>[...e[0]||(e[0]=[p(" ← VOLVER AL INICIO ",-1)])]),_:1}),e[1]||(e[1]=l('<div class="bg-white border-2 border-zinc-900 p-6 md:p-10 shadow-[8px_8px_0px_rgba(24,24,27,1)] relative"><h1 class="font-header text-4xl md:text-5xl mb-8 uppercase text-zinc-900 border-b-4 border-zinc-900 pb-4">Aviso Legal</h1><div class="space-y-6"><section><h2 class="font-header text-2xl mt-8 mb-4 uppercase text-zinc-900">1. Información General</h2><p class="font-body text-lg leading-relaxed mb-4 text-zinc-800">En cumplimiento con el deber de información recogido en artículo 10 de la Ley 34/2002, de 11 de julio, de Servicios de la Sociedad de la Información y del Comercio Electrónico (LSSI-CE), se reflejan los siguientes datos: el titular de dominio web es Tortillas Kombat (en adelante &quot;El Titular&quot;), con domicilio a estos efectos en Madrid.</p></section><section><h2 class="font-header text-2xl mt-8 mb-4 uppercase text-zinc-900">2. Propiedad Intelectual e Industrial</h2><p class="font-body text-lg leading-relaxed mb-4 text-zinc-800">El Titular por sí o como cesionario, es titular de todos los derechos de propiedad intelectual e industrial de su página web, así como de los elementos contenidos en la misma (a título enunciativo, imágenes, sonido, audio, vídeo, software o textos; marcas o logotipos, combinaciones de colores, estructura y diseño, etc.). Todos los derechos reservados.</p></section><section><h2 class="font-header text-2xl mt-8 mb-4 uppercase text-zinc-900">3. Exclusión de Garantías y Responsabilidad</h2><p class="font-body text-lg leading-relaxed mb-4 text-zinc-800">El Titular no se hace responsable, en ningún caso, de los daños y perjuicios de cualquier naturaleza que pudieran ocasionar, a título enunciativo: errores u omisiones en los contenidos, falta de disponibilidad del portal o la transmisión de virus o programas maliciosos o lesivos en los contenidos, a pesar de haber adoptado todas las medidas tecnológicas necesarias para evitarlo.</p></section><section><h2 class="font-header text-2xl mt-8 mb-4 uppercase text-zinc-900">4. Modificaciones</h2><p class="font-body text-lg leading-relaxed mb-4 text-zinc-800">El Titular se reserva el derecho de efectuar sin previo aviso las modificaciones que considere oportunas en su portal, pudiendo cambiar, suprimir o añadir tanto los contenidos y servicios que se presten a través de la misma como la forma en la que éstos aparezcan presentados o localizados en su portal.</p></section></div></div>',1))])])}}});export{v as default};
